import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';
import ProgressChart from '../components/ProgressChart';
import AIInsightCard from '../components/AIInsightCard';
import AIConfidenceIndicator from '../components/AIConfidenceIndicator';

const Dashboard = () => {
  const { user } = useContext(AuthContext);
  const [stats, setStats] = useState({
    projects: 0,
    sprints: 0,
    tasks: 0,
    completedTasks: 0
  });
  const [recentProjects, setRecentProjects] = useState([]);
  const [aiInsights, setAiInsights] = useState([]);
  const [velocityData, setVelocityData] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [projectsRes, sprintsRes, tasksRes] = await Promise.all([
        api.get('/projects'),
        api.get('/sprints'),
        api.get('/tasks')
      ]);

      const projects = projectsRes.data.projects || [];
      const sprints = sprintsRes.data.sprints || [];
      const tasks = tasksRes.data.tasks || [];
      const completedSprints = sprints.filter(s => s.status === 'Completed');

      setStats({
        projects: projects.length,
        sprints: sprints.length,
        tasks: tasks.length,
        completedTasks: tasks.filter(t => t.status === 'Completed').length
      });

      setRecentProjects(projects.slice(0, 5));

      // Generate AI insights
      generateAIInsights(projects, sprints, tasks);

      // Prepare velocity chart data
      if (completedSprints.length > 0) {
        const velocityChartData = completedSprints.slice(-5).map(sprint => ({
          label: sprint.name || `Sprint ${sprint._id.slice(-4)}`,
          value: sprint.actualVelocity || 0
        }));
        setVelocityData(velocityChartData);
      }

      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setLoading(false);
    }
  };

  const generateAIInsights = (projects, sprints, tasks) => {
    const insights = [];
    const completedTasks = tasks.filter(t => t.status === 'Completed');
    const completionRate = tasks.length > 0 ? (completedTasks.length / tasks.length) * 100 : 0;

    // High-risk projects insight
    const highRiskProjects = projects.filter(p => p.riskLevel === 'High');
    if (highRiskProjects.length > 0) {
      insights.push({
        type: 'error',
        title: 'High-Risk Projects Detected',
        message: `You have ${highRiskProjects.length} project(s) with high risk levels. Consider reviewing risk factors and taking preventive actions.`,
        confidence: 85,
        actionable: (
          <Link to="/projects" className="btn btn-danger btn-sm">
            Review Projects
          </Link>
        )
      });
    }

    // Task completion insight
    if (completionRate < 70 && tasks.length > 5) {
      insights.push({
        type: 'warning',
        title: 'Low Task Completion Rate',
        message: `Your task completion rate is ${completionRate.toFixed(1)}%. This may indicate scope creep or underestimated effort.`,
        confidence: 75
      });
    } else if (completionRate >= 90 && tasks.length > 5) {
      insights.push({
        type: 'success',
        title: 'Excellent Task Completion',
        message: `Great work! You've completed ${completionRate.toFixed(1)}% of tasks. Keep up the momentum!`,
        confidence: 90
      });
    }

    // Sprint overload warning
    const activeSprints = sprints.filter(s => s.status === 'Active');
    const overloadedSprints = activeSprints.filter(s => 
      s.aiRecommendation?.overloadWarning === true
    );
    if (overloadedSprints.length > 0) {
      insights.push({
        type: 'warning',
        title: 'Sprint Overload Detected',
        message: `${overloadedSprints.length} active sprint(s) may be overloaded. Consider redistributing tasks or extending sprint duration.`,
        confidence: 80,
        actionable: (
          <Link to="/sprints" className="btn btn-warning btn-sm">
            Review Sprints
          </Link>
        )
      });
    }

    // Velocity trend insight
    const completedSprints = sprints.filter(s => s.status === 'Completed');
    if (completedSprints.length >= 2) {
      const recentVelocities = completedSprints.slice(-3).map(s => s.actualVelocity || 0);
      const avgVelocity = recentVelocities.reduce((a, b) => a + b, 0) / recentVelocities.length;
      const trend = recentVelocities[recentVelocities.length - 1] - recentVelocities[0];

      if (trend < -10) {
        insights.push({
          type: 'warning',
          title: 'Velocity Declining',
          message: `Sprint velocity has decreased by ${Math.abs(trend)} story points. Review sprint planning and team capacity.`,
          confidence: 70
        });
      } else if (trend > 10) {
        insights.push({
          type: 'success',
          title: 'Velocity Improving',
          message: `Sprint velocity has increased by ${trend} story points. Great progress!`,
          confidence: 75
        });
      }
    }

    setAiInsights(insights);
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        justifyContent: 'center', 
        minHeight: '60vh',
        gap: '20px'
      }}>
        <div style={{ 
          width: '80px', 
          height: '80px', 
          borderRadius: '20px', 
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: '40px',
          boxShadow: '0 8px 24px rgba(99, 102, 241, 0.3)',
          animation: 'pulse 2s ease-in-out infinite'
        }}>
          🤖
        </div>
        <p style={{ color: '#64748b', fontSize: '18px', fontWeight: '600' }}>
          Loading dashboard with AI insights...
        </p>
      </div>
    );
  }

  const completionRate = stats.tasks > 0 ? (stats.completedTasks / stats.tasks) * 100 : 0;

  return (
    <div className="fade-in">
      <div className="page-header">
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '12px' }}>
          <div style={{ 
            width: '60px', 
            height: '60px', 
            borderRadius: '16px', 
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '32px',
            boxShadow: '0 8px 16px rgba(99, 102, 241, 0.3)'
          }}>
            🤖
          </div>
          <div>
            <h1>AI-Powered Dashboard</h1>
            <p style={{ marginTop: '8px' }}>Welcome back, <strong style={{ color: '#6366f1' }}>{user.name}</strong>! Here's your project overview with AI insights.</p>
          </div>
        </div>
      </div>

      {/* AI Insights Section */}
      {aiInsights.length > 0 && (
        <div className="card" style={{ marginBottom: '32px' }}>
          <div className="card-header">
            <span>✨</span>
            AI Insights & Recommendations
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '16px' }}>
            {aiInsights.map((insight, idx) => (
              <AIInsightCard key={idx} {...insight} />
            ))}
          </div>
        </div>
      )}

      {/* Stats Cards */}
      <div className="grid" style={{ marginBottom: '40px' }}>
        <div className="stat-card" style={{ background: 'linear-gradient(135deg, #ffffff 0%, #f8fafc 100%)' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
            <h3>📁 Projects</h3>
            <div style={{ 
              width: '48px', 
              height: '48px', 
              borderRadius: '12px', 
              background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.1) 0%, rgba(99, 102, 241, 0.05) 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '24px'
            }}>
              📁
            </div>
          </div>
          <div className="stat-value">{stats.projects}</div>
          <div className="stat-change">
            {stats.projects > 0 ? '✅ Active' : 'No projects yet'}
          </div>
        </div>
        <div className="stat-card" style={{ background: 'linear-gradient(135deg, #ffffff 0%, #f0fdf4 100%)' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
            <h3>🏃 Sprints</h3>
            <div style={{ 
              width: '48px', 
              height: '48px', 
              borderRadius: '12px', 
              background: 'linear-gradient(135deg, rgba(16, 185, 129, 0.1) 0%, rgba(16, 185, 129, 0.05) 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '24px'
            }}>
              🏃
            </div>
          </div>
          <div className="stat-value" style={{ background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            {stats.sprints}
          </div>
          <div className="stat-change">
            {stats.sprints > 0 ? '✅ In progress' : 'No sprints yet'}
          </div>
        </div>
        <div className="stat-card" style={{ background: 'linear-gradient(135deg, #ffffff 0%, #fffbeb 100%)' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
            <h3>✅ Total Tasks</h3>
            <div style={{ 
              width: '48px', 
              height: '48px', 
              borderRadius: '12px', 
              background: 'linear-gradient(135deg, rgba(245, 158, 11, 0.1) 0%, rgba(245, 158, 11, 0.05) 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '24px'
            }}>
              ✅
            </div>
          </div>
          <div className="stat-value" style={{ background: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            {stats.tasks}
          </div>
          <div className="stat-change">
            {completionRate.toFixed(1)}% completed
          </div>
        </div>
        <div className="stat-card" style={{ background: 'linear-gradient(135deg, #ffffff 0%, #eff6ff 100%)' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
            <h3>🎯 Completed</h3>
            <div style={{ 
              width: '48px', 
              height: '48px', 
              borderRadius: '12px', 
              background: 'linear-gradient(135deg, rgba(59, 130, 246, 0.1) 0%, rgba(59, 130, 246, 0.05) 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '24px'
            }}>
              🎯
            </div>
          </div>
          <div className="stat-value" style={{ background: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            {stats.completedTasks}
          </div>
          <div className="progress-bar" style={{ marginTop: '16px', height: '8px' }}>
            <div 
              className="progress-fill" 
              style={{ width: `${completionRate}%` }}
            />
          </div>
        </div>
      </div>

      {/* Velocity Chart */}
      {velocityData.length > 0 && (
        <div className="card" style={{ marginBottom: '32px' }}>
          <div className="card-header">
            <span>📊</span>
            Sprint Velocity Trend (AI Analysis)
          </div>
          <ProgressChart 
            data={velocityData} 
            color="primary"
          />
          <AIConfidenceIndicator 
            confidence={0.82} 
            label="Prediction Accuracy"
          />
        </div>
      )}

      {/* Recent Projects */}
      <div className="card">
        <div className="card-header">
          <span>📋</span>
          Recent Projects
        </div>
        {recentProjects.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '40px' }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>📁</div>
            <p style={{ color: '#6b7280', marginBottom: '16px' }}>
              No projects yet.
            </p>
            {user.role === 'PM' && (
              <Link to="/projects" className="btn btn-primary">
                Create Your First Project
              </Link>
            )}
          </div>
        ) : (
          <div className="table-container" style={{ overflowX: 'auto' }}>
            <table className="table">
              <thead>
                <tr>
                  <th>Project Name</th>
                  <th>Team Size</th>
                  <th>Risk Level</th>
                  <th>AI Risk Score</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {recentProjects.map(project => (
                  <tr key={project._id}>
                    <td>
                      <strong>{project.name}</strong>
                    </td>
                    <td>
                      <span className="badge badge-info">
                        {project.teamMembers?.length || 0} members
                      </span>
                    </td>
                    <td>
                      <span className={`risk-${project.riskLevel?.toLowerCase() || 'low'}`}>
                        {project.riskLevel || 'Low'}
                      </span>
                    </td>
                    <td>
                      {project.riskScore > 0 ? (
                        <AIConfidenceIndicator 
                          confidence={1 - (project.riskScore / 100)} 
                          label=""
                        />
                      ) : (
                        <span style={{ color: '#9ca3af' }}>Not analyzed</span>
                      )}
                    </td>
                    <td>
                      <Link to={`/projects/${project._id}`} className="btn btn-primary btn-sm">
                        View Details
                      </Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
